import os
from flask import Flask, request, redirect, url_for, flash
from werkzeug.utils import secure_filename

UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16 MB max upload size
app.secret_key = 'super_secret_key_for_flash_messages' # Flash mesajları için gerekli

# Yükleme klasörünü oluştur
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/', methods=['GET', 'POST'])
def upload_file():
    if request.method == 'POST':
        # Dosya kısmının isteğe dahil olup olmadığını kontrol et
        if 'file' not in request.files:
            flash('Dosya kısmı yok')
            return redirect(request.url)

        file = request.files['file']

        # Kullanıcı dosya seçmezse, tarayıcı boş bir kısım gönderir
        if file.filename == '':
            flash('Dosya seçilmedi')
            return redirect(request.url)

        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
            flash(f'Dosya "{filename}" başarıyla yüklendi.')
            return redirect(url_for('upload_file'))
        else:
            flash('İzin verilen dosya türleri: txt, pdf, png, jpg, jpeg, gif')
            return redirect(request.url)

    return '''
    <!doctype html>
    <title>Dosya Yükle</title>
    <h1>Yeni Dosya Yükle</h1>
    <form method=post enctype=multipart/form-data>
      <input type=file name=file>
      <input type=submit value=Yükle>
    </form>
    '''

if __name__ == '__main__':
    app.run(debug=True)
